     1→// CortexBuild Ultimate — Local API auth helpers (replaces Supabase)
     2→
     3→const TOKEN_KEY = 'cortexbuild_token';
     4→const USER_KEY  = 'cortexbuild_user';
     5→
     6→export function getToken(): string | null {
     7→  return localStorage.getItem(TOKEN_KEY);
     8→}
     9→
    10→export function setToken(token: string): void {
    11→  localStorage.setItem(TOKEN_KEY, token);
    12→}
    13→
    14→export function clearToken(): void {
    15→  localStorage.removeItem(TOKEN_KEY);
    16→  localStorage.removeItem(USER_KEY);
    17→}
    18→
    19→export function getStoredUser(): Record<string, unknown> | null {
    20→  const raw = localStorage.getItem(USER_KEY);
    21→  try { return raw ? JSON.parse(raw) : null; } catch { return null; }
    22→}
    23→
    24→export function setStoredUser(user: Record<string, unknown>): void {
    25→  localStorage.setItem(USER_KEY, JSON.stringify(user));
    26→}
    27→
    28→export const API_BASE = '/api';
    29→

