    83→      loading,
    84→      isAuthenticated: !!user,
    85→      signIn,
    86→      signUp,
    87→      signOut,
    88→      updateProfile,
    89→    }}>
    90→      {children}
    91→    </AuthContext.Provider>
    92→  );
    93→}
